import React from 'react';
import { Portal as CarbonPortal } from '@carbon/react';

const Portal = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonPortal
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonPortal>
    );
};

Portal.defaultProps = {
    className: ''
};

export default Portal;
